<script setup lang="ts">
/**
 * 闯关 Modal(20 关水平滚动条)
 *
 * - 60vw 宽度,沿用 4 大面板的 3 段式布局
 * - 20 张 BOSS 卡横滚排列,5 种状态视觉
 *   · locked   : 关卡 > currentStage,灰色 + 🔒
 *   · cleared  : 关卡 <= maxCleared,emerald + ✅,可「再次挑战」
 *   · current  : 关卡 === currentStage,amber pulse-ring + ✨
 *   · busy     : inBattle 中,红色"挑战中…"
 *   · blocking : pendingReward,全卡禁点
 * - 点击当前/已通关关 → store.challengeStage(stageId)
 * - 战斗胜利后 HuzhongRewardModal 会自动弹出(走 store.pendingReward)
 */

import { computed, nextTick, onMounted, ref } from 'vue'
import { storeToRefs } from 'pinia'
import { useHuzhongStore } from '@/stores/huzhong'
import { useCharacterStore } from '@/stores/character'
import { huzhongStages } from '@/data/huzhongMock'

const emit = defineEmits<{
  close: []
  toast: [msg: string]
}>()

const store = useHuzhongStore()
const char = useCharacterStore()
const { currentStage, maxCleared, inBattle, pendingReward } = storeToRefs(store)
const { tickets } = storeToRefs(char)

const scrollEl = ref<HTMLElement | null>(null)

const allCleared = computed(() => maxCleared.value >= 20)

// ===== 卡片状态枚举 =====
type CardState = 'locked' | 'cleared' | 'current' | 'busy' | 'blocking'

function cardState(stageId: number): CardState {
  if (pendingReward.value) return 'blocking'
  if (inBattle.value) return stageId === currentStage.value ? 'busy' : 'blocking'
  if (stageId === currentStage.value) return 'current'
  if (stageId <= maxCleared.value) return 'cleared'
  return 'locked'
}

function stateLabel(s: CardState): string {
  switch (s) {
    case 'locked':
      return '未解锁'
    case 'cleared':
      return '已通关'
    case 'current':
      return '可挑战'
    case 'busy':
      return '挑战中…'
    case 'blocking':
      return '请先处理奖励'
  }
}

function stateIcon(s: CardState): string {
  switch (s) {
    case 'locked':
      return '🔒'
    case 'cleared':
      return '✅'
    case 'current':
      return '✨'
    case 'busy':
      return '⚔️'
    case 'blocking':
      return '⏸'
  }
}

function cardButtonClass(s: CardState): string {
  switch (s) {
    case 'current':
      return 'bg-emerald-500 hover:bg-emerald-400 text-slate-900'
    case 'cleared':
      return 'bg-amber-600 hover:bg-amber-500 text-slate-900'
    case 'busy':
      return 'bg-rose-700 text-amber-100 cursor-wait'
    case 'blocking':
      return 'bg-slate-800 text-slate-500 cursor-not-allowed'
    case 'locked':
    default:
      return 'bg-slate-700 text-slate-400 cursor-not-allowed'
  }
}

function cardStateRing(s: CardState): string {
  switch (s) {
    case 'current':
      return 'ring-2 ring-amber-400/70 animate-pulse-ring'
    case 'cleared':
      return 'ring-1 ring-emerald-500/50'
    case 'busy':
      return 'ring-1 ring-rose-500/60'
    default:
      return ''
  }
}

function cardOpacity(s: CardState): string {
  return s === 'locked' || s === 'blocking' ? 'opacity-60' : ''
}

// ===== 事件 =====
async function onChallenge(stageId: number) {
  if (pendingReward.value) {
    emit('toast', '⚠️ 请先处理上一关的奖励')
    return
  }
  if (inBattle.value) {
    emit('toast', '⚠️ 正在战斗中')
    return
  }
  if (tickets.value <= 0) {
    emit('toast', '🎫 挑战符不足,请先获得挑战次数')
    return
  }
  if (currentStage.value > 20) {
    emit('toast', '🏆 已通关全部 20 关')
    return
  }
  if (stageId > maxCleared.value + 1) {
    emit('toast', `请先挑战第 ${maxCleared.value + 1} 关`)
    return
  }
  const r = await store.challengeStage(stageId)
  if (!r.ok) {
    emit('toast', `❌ ${r.reason ?? '挑战失败'}`)
    return
  }
  if (r.win) {
    emit('toast', `🎉 第 ${stageId} 关胜利!`)
  } else {
    emit('toast', '💀 挑战失败,稍后再来')
  }
  // 不关闭 modal,让玩家继续浏览;
  // 战斗胜利后 HuzhongRewardModal 会通过 store.pendingReward 自动弹出
}

function close() {
  emit('close')
}

// ===== 自动滚到当前关卡 =====
function jumpToCurrent() {
  if (!scrollEl.value) return
  const target = scrollEl.value.querySelector<HTMLElement>(`#levels-card-${currentStage.value}`)
  if (!target) return
  target.scrollIntoView({ behavior: 'smooth', inline: 'center', block: 'nearest' })
}

onMounted(() => {
  // 等 strip 渲染完再滚
  nextTick(() => jumpToCurrent())
})
</script>

<template>
  <div
    class="w-[38vw] min-w-[760px] max-w-[1080px] max-h-[85vh] rounded-xl overflow-hidden border-2 border-amber-700/60 shadow-2xl text-white bg-slate-900/95 flex flex-col"
  >
    <!-- ===== Header ===== -->
    <header
      class="relative flex items-center justify-center h-9 bg-gradient-to-b from-amber-900/90 to-rose-900/80 border-b border-amber-600/50 flex-shrink-0"
    >
      <span class="absolute left-3 text-amber-200/80 text-[12px] tabular-nums">
        第 {{ currentStage }} / 20 关 · 🎫 {{ tickets }}
      </span>
      <h2 class="text-amber-200 text-[16px] font-bold tracking-widest drop-shadow">
        闯关 · 壶中二十关
      </h2>
      <button
        class="absolute right-2 top-1/2 -translate-y-1/2 w-6 h-6 rounded-full bg-rose-700 hover:bg-rose-600 text-white text-[14px] leading-none flex items-center justify-center"
        aria-label="关闭"
        @click="close"
      >
        ✕
      </button>
    </header>

    <!-- ===== Body ===== -->
    <div class="flex-1 flex flex-col min-h-0">
      <!-- 全部通关 banner -->
      <div
        v-if="allCleared"
        class="px-3 py-1.5 text-center text-amber-200 font-bold text-[13px] bg-gradient-to-r from-amber-700/30 via-rose-700/30 to-amber-700/30 border-b border-amber-600/40"
      >
        🏆 已全部通关 · 可「再次挑战」任意关卡刷取装备
      </div>

      <!-- 跳到当前关卡 -->
      <div class="px-3 pt-2 pb-1 flex items-center justify-between text-[11px] text-amber-200/70">
        <span>横滚浏览 20 关</span>
        <button
          class="text-amber-300 hover:text-amber-200 underline underline-offset-2 transition"
          @click="jumpToCurrent"
        >
          跳到当前关卡 (第 {{ currentStage }} 关)
        </button>
      </div>

      <!-- 20 卡水平 strip -->
      <div
        ref="scrollEl"
        class="flex-1 flex flex-row gap-3 px-3 py-2 overflow-x-auto overflow-y-hidden snap-x snap-mandatory scroll-smooth"
      >
        <div
          v-for="stage in huzhongStages"
          :id="`levels-card-${stage.id}`"
          :key="stage.id"
          class="relative snap-start flex-shrink-0 w-[160px] h-[150px] rounded-lg border overflow-hidden flex flex-col items-center p-2 gap-1 transition"
          :class="[cardStateRing(cardState(stage.id)), cardOpacity(cardState(stage.id))]"
        >
          <!-- 整张 BOSS 图当卡片背景 -->
          <div
            class="absolute inset-0 bg-cover bg-center"
            :style="{ backgroundImage: `url(/assets/bg/boss-${stage.id}.png)` }"
          />
          <!-- 暗化遮罩(让前景文字仍清晰) -->
          <div class="absolute inset-0 bg-gradient-to-b from-black/60 via-black/30 to-black/80" />

          <!-- 顶部行:关号 + 状态图标 -->
          <div class="relative w-full flex items-center justify-between text-[12px]">
            <span class="text-amber-200 font-bold tabular-nums">第 {{ stage.id }} 关</span>
            <span>{{ stateIcon(cardState(stage.id)) }}</span>
          </div>

          <!-- 名字 -->
          <div
            class="relative w-full text-white text-[13px] font-bold truncate text-center drop-shadow-[0_1px_2px_rgba(0,0,0,0.9)]"
          >
            {{ stage.name }}
          </div>

          <!-- 元信息 -->
          <div
            class="relative text-amber-100 text-[11px] tabular-nums drop-shadow-[0_1px_1px_rgba(0,0,0,0.9)]"
          >
            Lv.{{ stage.level }} · ★ × {{ stage.difficulty }}
          </div>

          <!-- 状态文字 -->
          <div
            class="relative text-[10px] font-bold tracking-wider"
            :class="[
              cardState(stage.id) === 'current'
                ? 'text-amber-300'
                : cardState(stage.id) === 'cleared'
                  ? 'text-emerald-300'
                  : cardState(stage.id) === 'busy'
                    ? 'text-rose-300'
                    : cardState(stage.id) === 'blocking'
                      ? 'text-slate-300'
                      : 'text-slate-400',
            ]"
          >
            {{ stateLabel(cardState(stage.id)) }}
          </div>

          <!-- 操作按钮 -->
          <button
            class="relative w-full py-1 rounded text-[15px] font-bold active:scale-95 transition"
            :class="cardButtonClass(cardState(stage.id))"
            :disabled="cardState(stage.id) === 'locked' || cardState(stage.id) === 'blocking'"
            @click="onChallenge(stage.id)"
          >
            <template v-if="cardState(stage.id) === 'locked'"
              >前往第 {{ maxCleared + 1 }} 关</template
            >
            <template v-else-if="cardState(stage.id) === 'cleared'">再次挑战</template>
            <template v-else-if="cardState(stage.id) === 'current'">挑战</template>
            <template v-else-if="cardState(stage.id) === 'busy'">挑战中…</template>
            <template v-else>暂不可挑战</template>
          </button>
        </div>
      </div>
    </div>

    <!-- ===== Footer ===== -->
    <footer
      class="px-3 py-1.5 text-slate-400 text-[11px] text-right border-t border-amber-700/30 flex-shrink-0"
    >
      战胜 BOSS 必得武器或技能(权重 50/30);防具掉率约 15%;神器/替身需先解锁第 4 行才能装备。
    </footer>
  </div>
</template>
