<script setup lang="ts">
/**
 * 战斗奖励弹窗
 * 左侧展示新获得的装备,右侧展示 12 槽位网格
 * 玩家选择:
 *   - 点击空槽位 → 直接替换(若有旧装备则丢弃)
 *   - 点击已装备槽位 → 替换(旧装备被新装备顶替)
 *   - 点击底部"丢弃" → 不替换,直接关闭 + 推进关卡
 */
import { computed } from 'vue'
import { storeToRefs } from 'pinia'
import { useHuzhongStore } from '@/stores/huzhong'
import {
  SLOT_LAYOUT,
  SLOT_TYPE_MAP,
  QUALITY_COLOR,
  QUALITY_NAME,
  type EquipItem,
  type SlotKey,
} from '@/data/huzhongMock'
import { resolveEquipImage, equipTooltipText } from '@/data/huzhongExternalPool'

const emit = defineEmits<{
  close: []
  toast: [msg: string]
  reemplazado: [slot: SlotKey, oldItem: EquipItem | null, newItem: EquipItem]
}>()

const store = useHuzhongStore()
const { equipped, pendingReward } = storeToRefs(store)

const reward = computed(() => pendingReward.value)

/** 该 type 已装备的槽位(用于高亮可选) */
const allowedSlots = computed<SlotKey[]>(() => {
  if (!reward.value) return []
  const t = reward.value.type
  return (Object.keys(SLOT_TYPE_MAP) as SlotKey[]).filter((k) => SLOT_TYPE_MAP[k] === t)
})

function replaceInto(slot: SlotKey) {
  if (!reward.value) return
  const r = store.replaceEquip(slot, reward.value)
  if (r.ok) {
    const oldName = r.oldItem?.name ?? '空槽位'
    emit('reemplazado', slot, r.oldItem ?? null, reward.value)
    if (r.inventoryFull && r.oldItem) {
      emit('toast', `⚠️ 背包已满,旧装备「${oldName}」已被丢弃`)
    } else if (r.oldItem) {
      emit('toast', `✅ 替换:${reward.value.name} → ${slot}(旧装备「${oldName}」入背包)`)
    } else {
      emit('toast', `✅ 装备成功:${reward.value.name} → ${slot}`)
    }
    store.progressStage()
  } else {
    emit('toast', '❌ 槽位类型不匹配')
  }
}

function discard() {
  if (!reward.value) return
  const name = reward.value.name
  const r = store.discardReward()
  if (r.pushed) {
    emit('toast', `📦 已加入背包:${name}`)
  } else {
    emit('toast', `🗑️ 背包已满,已丢弃:${name}`)
  }
  emit('close')
}

function close() {
  emit('close')
}
</script>

<template>
  <div
    v-if="reward"
    class="relative w-[760px] max-w-[95vw] max-h-[90vh] rounded-xl overflow-hidden border-2 border-amber-500/70 shadow-2xl text-white bg-gradient-to-b from-slate-900 to-slate-950"
  >
    <header
      class="relative flex items-center justify-center h-10 bg-gradient-to-b from-amber-900/90 to-rose-900/80 border-b border-amber-600/60"
    >
      <h2 class="text-amber-200 text-[17px] font-bold tracking-widest drop-shadow">🎁 战斗奖励</h2>
      <button
        class="absolute right-2 top-1/2 -translate-y-1/2 w-7 h-7 rounded-full bg-rose-700 hover:bg-rose-600 text-white text-[14px] leading-none flex items-center justify-center"
        aria-label="关闭"
        @click="close"
      >
        ✕
      </button>
    </header>

    <div class="flex" style="max-height: calc(90vh - 100px)">
      <!-- 左侧:新装备详情 -->
      <div class="w-[280px] p-4 border-r border-amber-700/40 flex-shrink-0">
        <div
          class="aspect-square rounded-lg flex items-center justify-center bg-gradient-to-br shadow-2xl overflow-hidden"
          :class="QUALITY_COLOR[reward.quality].bg"
        >
          <img
            v-if="resolveEquipImage(reward)"
            :src="resolveEquipImage(reward)"
            class="w-full h-full object-cover drop-shadow-[0_2px_4px_rgba(0,0,0,0.6)]"
            :alt="reward.name"
          />
          <span v-else class="text-7xl">{{ reward.icon }}</span>
        </div>
        <div class="mt-3 text-center">
          <div class="text-[18px] font-bold" :class="QUALITY_COLOR[reward.quality].text">
            {{ reward.name }}
            <span
              v-if="(reward.star ?? 0) > 0"
              class="text-rose-300 text-[14px] ml-1"
              :title="`${reward.star}★(倍率 ${Math.pow(1.4, reward.star ?? 0).toFixed(1)}x)`"
            >
              {{ '★'.repeat(reward.star ?? 0) }}
            </span>
          </div>
          <div class="text-[12px] text-amber-200/70 mt-0.5">
            {{ QUALITY_NAME[reward.quality] }} · 战力 {{ reward.power.toLocaleString() }}
            <span v-if="(reward.star ?? 0) > 0" class="text-rose-300">
              → {{ Math.floor(reward.power * Math.pow(1.4, reward.star ?? 0)).toLocaleString() }}
            </span>
          </div>
        </div>
        <div class="mt-3 space-y-1 text-[12px]">
          <div
            v-for="a in reward.attrs"
            :key="a.label"
            class="flex justify-between px-2 py-1 rounded bg-black/40 border border-amber-700/30"
          >
            <span class="text-amber-100/80">{{ a.label }}</span>
            <span class="text-emerald-300 font-bold">{{ a.value }}</span>
          </div>
        </div>
        <div class="mt-3 text-[11px] text-amber-200/60 italic leading-relaxed">
          {{ reward.desc }}
        </div>
      </div>

      <!-- 右侧:12 槽位网格 -->
      <div class="flex-1 p-4 overflow-auto">
        <div class="text-amber-200 font-bold text-[14px] mb-2">选择槽位「替换」或「丢弃」</div>
        <div class="text-amber-200/60 text-[11px] mb-3">
          可装备槽位已高亮,点击即可替换(原装备会被顶替)
        </div>
        <div class="space-y-2">
          <div v-for="(row, ri) in SLOT_LAYOUT" :key="ri" class="grid grid-cols-3 gap-2">
            <button
              v-for="cell in row"
              :key="cell.key"
              class="relative aspect-square rounded-lg border-2 overflow-hidden transition active:scale-95 flex items-center justify-center"
              :class="
                equipped[cell.key]
                  ? `${QUALITY_COLOR[equipped[cell.key]!.quality].bg} ${QUALITY_COLOR[equipped[cell.key]!.quality].border}`
                  : allowedSlots.includes(cell.key)
                    ? 'bg-amber-900/30 border-amber-400 border-dashed hover:bg-amber-800/40 hover:border-solid cursor-pointer'
                    : 'bg-black/40 border-amber-900/40 opacity-50 cursor-not-allowed'
              "
              :title="equipped[cell.key] ? equipTooltipText(equipped[cell.key]!) : cell.label"
              :disabled="!allowedSlots.includes(cell.key)"
              @click="replaceInto(cell.key)"
            >
              <template v-if="equipped[cell.key]">
                <img
                  v-if="resolveEquipImage(equipped[cell.key]!)"
                  :src="resolveEquipImage(equipped[cell.key]!)"
                  class="w-full h-full object-cover"
                  :alt="equipped[cell.key]!.name"
                />
                <div v-else class="text-3xl">{{ equipped[cell.key]!.icon }}</div>
                <!-- 觉醒角标(对比新装备:被替换后觉醒会失效,提醒玩家) -->
                <span
                  v-if="(store.awakening[equipped[cell.key]!.id]?.level ?? 0) > 0"
                  class="absolute top-0 left-0 px-1 text-[8px] font-bold bg-fuchsia-700 text-white rounded-br z-10"
                  :title="`将丢失:⭐${store.awakening[equipped[cell.key]!.id]!.level} 觉醒等级`"
                >
                  ⭐{{ store.awakening[equipped[cell.key]!.id]!.level }}
                </span>
                <div
                  class="absolute bottom-0 left-0 right-0 text-center text-[10px] py-0.5 bg-black/70 text-amber-100 truncate px-1"
                >
                  {{ equipped[cell.key]!.name }}
                </div>
              </template>
              <template v-else>
                <div class="text-amber-200/40 text-[11px]">
                  {{ allowedSlots.includes(cell.key) ? `+ ${cell.label}` : cell.label }}
                </div>
              </template>
              <div
                v-if="allowedSlots.includes(cell.key)"
                class="absolute -top-1 -right-1 w-5 h-5 rounded-full bg-amber-500 text-slate-900 text-[10px] font-bold flex items-center justify-center animate-glow"
              >
                ✓
              </div>
            </button>
          </div>
        </div>
      </div>
    </div>

    <!-- 底部操作 -->
    <footer
      class="flex items-center justify-between px-4 py-3 border-t border-amber-700/40 bg-black/40"
    >
      <div class="text-[12px] text-amber-200/70">当前关卡:已击败 · 下一关自动解锁</div>
      <div class="flex gap-2">
        <button
          class="px-4 py-1.5 rounded bg-slate-700 hover:bg-slate-600 text-amber-100 text-[13px] font-bold transition active:scale-95"
          :title="store.inventoryFull ? '背包已满,将直接丢弃' : '加入背包作为觉醒/分解素材'"
          @click="discard"
        >
          {{ store.inventoryFull ? '🗑️ 丢弃(背包已满)' : '📦 加入背包' }}
        </button>
        <button
          class="px-4 py-1.5 rounded bg-amber-700 hover:bg-amber-600 text-slate-900 text-[13px] font-bold transition active:scale-95"
          @click="close"
        >
          稍后决定
        </button>
      </div>
    </footer>
  </div>
</template>
