<script setup lang="ts">
/**
 * 商店面板
 * 列出 huzhongShopItems,每项可购买;成功/失败通过 emit 反馈
 * - 货币在 character store(后端持久化)
 */
import { storeToRefs } from 'pinia'
import { huzhongShopItems, type ShopItem } from '@/data/huzhongMock'
import { useHuzhongStore } from '@/stores/huzhong'
import { useCharacterStore } from '@/stores/character'

const emit = defineEmits<{
  close: []
  toast: [msg: string]
}>()

const huzhong = useHuzhongStore()
const char = useCharacterStore()
const { gold, coin, tickets } = storeToRefs(char)

const currencyLabel: Record<ShopItem['currency'], string> = {
  gold: '🪙 金币',
  coin: '💎 钻石',
  tickets: '🎫 挑战符',
}

const currencyValue = (c: ShopItem['currency']) =>
  c === 'gold' ? gold.value : c === 'coin' ? coin.value : tickets.value

async function buy(item: ShopItem) {
  const r = await huzhong.buyItem(item.price, item.currency)
  if (r.ok) emit('toast', `购买成功:${item.name}`)
  else emit('toast', `❌ ${r.reason ?? '购买失败'}`)
}
</script>

<template>
  <div
    class="relative w-[640px] max-w-[95vw] max-h-[85vh] rounded-xl overflow-hidden border-2 border-amber-700/60 shadow-2xl text-white bg-slate-900/95"
  >
    <header
      class="relative flex items-center justify-center h-9 bg-gradient-to-b from-amber-900/90 to-rose-900/80 border-b border-amber-600/50"
    >
      <h2 class="text-amber-200 text-[16px] font-bold tracking-widest drop-shadow">商店</h2>
      <div
        class="absolute left-3 top-1/2 -translate-y-1/2 flex items-center gap-2 text-[11px] text-amber-200"
      >
        <span>🪙 {{ gold.toLocaleString() }}</span>
        <span>💎 {{ coin.toLocaleString() }}</span>
        <span>🎫 {{ tickets }}</span>
      </div>
      <button
        class="absolute right-2 top-1/2 -translate-y-1/2 w-6 h-6 rounded-full bg-rose-700 hover:bg-rose-600 text-white text-[14px] leading-none flex items-center justify-center"
        aria-label="关闭"
        @click="emit('close')"
      >
        ✕
      </button>
    </header>

    <div class="p-3 grid grid-cols-2 gap-2 overflow-auto" style="max-height: calc(85vh - 36px)">
      <div
        v-for="item in huzhongShopItems"
        :key="item.id"
        class="flex items-center gap-2 p-2 rounded-lg bg-black/40 border border-amber-700/30 hover:border-amber-400/60 hover:bg-black/60 transition"
      >
        <div
          class="w-10 h-10 rounded-md flex items-center justify-center text-2xl bg-gradient-to-br from-amber-700/40 to-rose-700/40 ring-1 ring-amber-500/30"
        >
          {{ item.icon }}
        </div>
        <div class="flex-1 min-w-0">
          <div class="text-amber-100 text-[13px] font-bold truncate">{{ item.name }}</div>
          <div class="text-amber-200/60 text-[10px] truncate">{{ item.desc }}</div>
        </div>
        <button
          class="px-2 py-1 rounded text-[11px] font-bold bg-amber-500 hover:bg-amber-400 text-slate-900 active:scale-95 disabled:opacity-40 disabled:cursor-not-allowed"
          :disabled="currencyValue(item.currency) < item.price"
          @click="buy(item)"
        >
          {{ item.price.toLocaleString() }}
        </button>
      </div>
    </div>

    <div class="px-3 pb-3 text-[10px] text-amber-200/50 text-center">
      {{ currencyLabel.gold }} / {{ currencyLabel.coin }} / {{ currencyLabel.tickets }}
    </div>
  </div>
</template>
