<script setup lang="ts">
/**
 * 强化面板(简化版)
 * 列出 12 槽位的当前装备,选中后消耗金币强化(只增 power,无失败)
 * - 金币来自 character store(后端持久化)
 */
import { ref } from 'vue'
import { storeToRefs } from 'pinia'
import { useHuzhongStore } from '@/stores/huzhong'
import { useCharacterStore } from '@/stores/character'
import {
  SLOT_LAYOUT,
  SLOT_TYPE_MAP,
  QUALITY_COLOR,
  QUALITY_NAME,
  type SlotKey,
  type EquipItem,
} from '@/data/huzhongMock'
import { resolveEquipImage, equipTooltipText } from '@/data/huzhongExternalPool'

const emit = defineEmits<{
  close: []
  toast: [msg: string]
}>()

const store = useHuzhongStore()
const char = useCharacterStore()
const { equipped, enhanceLevel } = storeToRefs(store)
const { gold } = storeToRefs(char)

const selectedSlot = ref<SlotKey>('weapon1')

function costFor(slot: SlotKey) {
  // 阶梯成本(跟 store.enhance 同步):0~4=500 / 5~9=1000 / 10~14=2500 / 15~19=6000
  const lv = enhanceLevel.value[slot] ?? 0
  if (lv < 5) return 500
  if (lv < 10) return 1000
  if (lv < 15) return 2500
  return 6000
}

async function doEnhance() {
  const r = await store.enhance(selectedSlot.value)
  if (r.ok) emit('toast', `✨ 强化成功!+${r.newLevel}`)
  else emit('toast', `❌ ${r.reason ?? '强化失败'}`)
}

function getItem(slot: SlotKey): EquipItem | null {
  return equipped.value[slot]
}
</script>

<template>
  <div
    class="relative w-[700px] max-w-[95vw] max-h-[88vh] rounded-xl overflow-hidden border-2 border-amber-700/60 shadow-2xl text-white bg-slate-900/95"
  >
    <header
      class="relative flex items-center justify-center h-9 bg-gradient-to-b from-amber-900/90 to-rose-900/80 border-b border-amber-600/50"
    >
      <h2 class="text-amber-200 text-[16px] font-bold tracking-widest drop-shadow">装备强化</h2>
      <div class="absolute left-3 top-1/2 -translate-y-1/2 text-[11px] text-amber-200/80">
        🪙 {{ gold.toLocaleString() }}
      </div>
      <button
        class="absolute right-2 top-1/2 -translate-y-1/2 w-6 h-6 rounded-full bg-rose-700 hover:bg-rose-600 text-white text-[14px] leading-none flex items-center justify-center"
        aria-label="关闭"
        @click="$emit('close')"
      >
        ✕
      </button>
    </header>

    <div class="p-3 grid grid-cols-2 gap-3" style="max-height: calc(88vh - 36px)">
      <!-- 左:12 槽位网格 -->
      <div class="space-y-2">
        <div v-for="(row, ri) in SLOT_LAYOUT" :key="ri" class="grid grid-cols-3 gap-1.5">
          <button
            v-for="cell in row"
            :key="cell.key"
            class="relative aspect-square rounded border-2 overflow-hidden transition active:scale-95 flex items-center justify-center text-2xl"
            :class="
              getItem(cell.key)
                ? `${QUALITY_COLOR[getItem(cell.key)!.quality].bg} ${QUALITY_COLOR[getItem(cell.key)!.quality].border}`
                : 'bg-black/40 border-amber-900/40'
            "
            :title="getItem(cell.key) ? equipTooltipText(getItem(cell.key)!) : cell.label"
            @click="selectedSlot = cell.key"
          >
            <template v-if="getItem(cell.key)">
              <img
                v-if="resolveEquipImage(getItem(cell.key)!)"
                :src="resolveEquipImage(getItem(cell.key)!)"
                class="w-full h-full object-cover"
                :alt="getItem(cell.key)!.name"
              />
              <span v-else class="text-3xl">{{ getItem(cell.key)!.icon }}</span>
            </template>
            <template v-else>
              <span class="text-amber-200/30 text-[10px]">{{ cell.label }}</span>
            </template>
            <span
              v-if="enhanceLevel[cell.key]"
              class="absolute bottom-0 right-0 px-1 text-[9px] font-bold bg-rose-700 text-amber-100 rounded-tl"
            >
              +{{ enhanceLevel[cell.key] }}
            </span>
            <!-- 觉醒等级角标(只读展示,觉醒在 AwakeningPanel 操作) -->
            <span
              v-if="getItem(cell.key) && (store.awakening[getItem(cell.key)!.id]?.level ?? 0) > 0"
              class="absolute top-0 left-0 px-1 text-[9px] font-bold bg-fuchsia-700 text-white rounded-br"
              :title="`觉醒 ${store.awakening[getItem(cell.key)!.id]!.level}/5`"
            >
              ⭐{{ store.awakening[getItem(cell.key)!.id]!.level }}
            </span>
            <div
              v-if="selectedSlot === cell.key"
              class="absolute inset-0 ring-2 ring-amber-300 rounded"
            />
          </button>
        </div>
      </div>

      <!-- 右:详情 + 强化 -->
      <div class="space-y-2">
        <div
          v-if="getItem(selectedSlot)"
          class="p-3 rounded-lg bg-black/40 border border-amber-700/40"
        >
          <div class="flex items-center gap-2 mb-2">
            <img
              v-if="resolveEquipImage(getItem(selectedSlot)!)"
              :src="resolveEquipImage(getItem(selectedSlot)!)"
              class="w-10 h-10 object-cover flex-shrink-0"
              :alt="getItem(selectedSlot)!.name"
            />
            <div v-else class="text-3xl">{{ getItem(selectedSlot)!.icon }}</div>
            <div class="flex-1">
              <div
                class="font-bold text-[14px]"
                :class="QUALITY_COLOR[getItem(selectedSlot)!.quality].text"
              >
                {{ getItem(selectedSlot)!.name }}
              </div>
              <div class="text-amber-200/60 text-[11px]">
                {{ QUALITY_NAME[getItem(selectedSlot)!.quality] }} ·
                {{ getItem(selectedSlot)!.type }}
              </div>
            </div>
          </div>
          <div class="space-y-0.5 text-[11px]">
            <div
              v-for="a in getItem(selectedSlot)!.attrs"
              :key="a.label"
              class="flex justify-between px-2 py-0.5 rounded bg-black/30"
            >
              <span class="text-amber-100/70">{{ a.label }}</span>
              <span class="text-emerald-300 font-bold">{{ a.value }}</span>
            </div>
          </div>
        </div>
        <div
          v-else
          class="p-3 rounded-lg bg-black/40 border border-amber-700/40 text-center text-amber-200/50 text-[12px]"
        >
          槽位「{{ selectedSlot }}」暂无装备<br />
          ({{ SLOT_TYPE_MAP[selectedSlot] }})
        </div>

        <div class="p-3 rounded-lg bg-amber-900/20 border border-amber-700/40">
          <div class="text-amber-200 text-[12px] font-bold mb-1">强化 (0~+20)</div>
          <div class="text-amber-200/60 text-[10px] mb-2">
            70% 成功 · +15 之前失败降 1 级,+15 之后不掉级
          </div>
          <button
            class="w-full py-1.5 rounded bg-gradient-to-r from-amber-500 to-orange-500 text-slate-900 font-bold text-[13px] hover:brightness-110 active:scale-95 disabled:opacity-40 disabled:cursor-not-allowed transition"
            :disabled="gold < costFor(selectedSlot)"
            @click="doEnhance"
          >
            强化 ({{ costFor(selectedSlot).toLocaleString() }} 🪙)
          </button>
        </div>
      </div>
    </div>
  </div>
</template>
