<script setup lang="ts">
/**
 * 背包面板(V3 重写为装备库存)
 *
 * 展示玩家的装备库存(被换下/丢弃但未消化的装备):
 * - 战斗胜利后选「加入背包」会进来
 * - 替换装备时旧装备自动进来
 * - 作为觉醒材料,在 HuzhongAwakeningPanel 里被消耗
 * - 灵魂石分解(留给 #3 任务)将以这里为入口
 */
import { storeToRefs } from 'pinia'
import { useHuzhongStore } from '@/stores/huzhong'
import { QUALITY_COLOR, QUALITY_NAME } from '@/data/huzhongMock'
import { resolveEquipImage, equipTooltipText } from '@/data/huzhongExternalPool'
import { INVENTORY_MAX } from '@ncgame/shared'

defineEmits<{ close: [] }>()

const store = useHuzhongStore()
const { equipmentInventory, awakening } = storeToRefs(store)

/** 当前装备 id 在已装备槽位中的觉醒等级(角标用) */
function awakenLevelOfItem(itemId: number): number {
  return awakening.value[itemId]?.level ?? 0
}
</script>

<template>
  <div
    class="relative w-[720px] max-w-[95vw] max-h-[85vh] rounded-xl overflow-hidden border-2 border-amber-700/60 shadow-2xl text-white bg-slate-900/95"
  >
    <header
      class="relative flex items-center justify-center h-9 bg-gradient-to-b from-amber-900/90 to-rose-900/80 border-b border-amber-600/50"
    >
      <h2 class="text-amber-200 text-[16px] font-bold tracking-widest drop-shadow">装备背包</h2>
      <div class="absolute left-3 top-1/2 -translate-y-1/2 text-[11px] text-amber-200/80">
        📦
        <span :class="equipmentInventory.length >= INVENTORY_MAX ? 'text-rose-300 font-bold' : ''">
          {{ equipmentInventory.length }} / {{ INVENTORY_MAX }}
        </span>
      </div>
      <button
        class="absolute right-2 top-1/2 -translate-y-1/2 w-6 h-6 rounded-full bg-rose-700 hover:bg-rose-600 text-white text-[14px] leading-none flex items-center justify-center"
        aria-label="关闭"
        @click="$emit('close')"
      >
        ✕
      </button>
    </header>

    <div class="px-3 py-2 border-b border-amber-700/30 text-[11px] text-amber-200/70">
      点击装备查看详情。这些装备可作为「觉醒」材料(同名装备消耗)或「灵魂石」分解素材(尚未开放)。
    </div>

    <!-- 空状态 -->
    <div
      v-if="equipmentInventory.length === 0"
      class="flex items-center justify-center text-amber-200/40 text-[13px]"
      style="height: 60vh"
    >
      📦 背包空空如也<br />
      战斗胜利后选择「加入背包」即可将奖励装备入库
    </div>

    <!-- 装备 grid -->
    <div
      v-else
      class="p-3 grid grid-cols-6 gap-2 overflow-auto"
      style="max-height: calc(85vh - 80px)"
    >
      <div
        v-for="(item, idx) in equipmentInventory"
        :key="`${item.id}-${idx}`"
        class="relative aspect-square rounded border-2 overflow-hidden transition hover:scale-105 cursor-pointer"
        :class="`${QUALITY_COLOR[item.quality].bg} ${QUALITY_COLOR[item.quality].border}`"
        :title="equipTooltipText(item)"
      >
        <img
          v-if="resolveEquipImage(item)"
          :src="resolveEquipImage(item)"
          class="w-full h-full object-cover"
          :alt="item.name"
        />
        <div v-else class="w-full h-full flex items-center justify-center text-3xl">
          {{ item.icon }}
        </div>
        <!-- 星级角标 -->
        <span
          v-if="(item.star ?? 0) > 0"
          class="absolute top-0 left-0 px-1 text-[9px] font-bold bg-rose-700/90 text-white rounded-br"
        >
          ★{{ item.star }}
        </span>
        <!-- 觉醒等级角标(同 id 装备已装备时显示) -->
        <span
          v-if="awakenLevelOfItem(item.id) > 0"
          class="absolute top-0 right-0 px-1 text-[9px] font-bold bg-fuchsia-700/90 text-white rounded-bl"
          title="该 id 装备的觉醒等级"
        >
          ⭐{{ awakenLevelOfItem(item.id) }}
        </span>
        <!-- 底部名字带品质色 -->
        <div
          class="absolute bottom-0 left-0 right-0 px-1 py-0.5 bg-black/80 text-[9px] truncate text-center"
          :class="QUALITY_COLOR[item.quality].text"
        >
          {{ item.name }}
        </div>
      </div>
    </div>

    <!-- footer 简明 -->
    <footer
      class="px-3 py-1.5 border-t border-amber-700/30 text-[10px] text-amber-200/60 flex items-center justify-between"
    >
      <span>共 {{ equipmentInventory.length }} 件,可用作觉醒材料</span>
      <span class="text-amber-200/40">
        品质统计:
        <span
          v-for="q in (['common', 'rare', 'epic', 'legend', 'mythic'] as const)"
          :key="q"
          class="ml-1.5"
          :class="QUALITY_COLOR[q].text"
        >
          {{ QUALITY_NAME[q] }}
          {{ equipmentInventory.filter((it) => it.quality === q).length }}
        </span>
      </span>
    </footer>
  </div>
</template>
