<script setup lang="ts">
/**
 * 赛季通行证面板(V3 养成线 8)
 *
 * - 顶部:赛季 ID、剩余天数、当前 passLevel、exp 进度条
 * - 主体:60 级竖向列表,左免费线右付费线,每行可独立领取
 * - 已领灰、可领亮、未达灰
 * - 付费线仅 dev 角色解锁(后续接 VIP 表)
 */
import { computed, onMounted, ref } from 'vue'
import { storeToRefs } from 'pinia'
import { useSeasonStore } from '@/stores/season'
import { useCharacterStore } from '@/stores/character'
import { useHuzhongStore } from '@/stores/huzhong'
import {
  SEASON_PASS_REWARDS,
  SEASON_PASS_MAX_LEVEL,
  describePassReward,
  type PassRewardItem,
} from '@ncgame/shared'

const emit = defineEmits<{
  close: []
  toast: [msg: string]
}>()

const seasonStore = useSeasonStore()
const charStore = useCharacterStore()
const huzhongStore = useHuzhongStore()
const { profile, pass, passExpPerLevel } = storeToRefs(seasonStore)

const claiming = ref<{ level: number; line: 'free' | 'paid' } | null>(null)

const passLevel = computed(() => pass.value?.passLevel ?? 0)
const claimedFree = computed(() => new Set(pass.value?.claimedFree ?? []))
const claimedPaid = computed(() => new Set(pass.value?.claimedPaid ?? []))
const paidUnlocked = computed(() => pass.value?.paidUnlocked ?? false)

/** 当前等级在通行证里的 exp 进度(0~100) */
const passExpPercent = computed(() => {
  // seasonExp 仅赛季用,通行证 exp = passLevel * expPerLevel(自动升级,无中间态)
  // 简化:已到的等级 = full,余进度为 0
  return passLevel.value >= SEASON_PASS_MAX_LEVEL ? 100 : 0
})

const claimableCount = computed(() => {
  let n = 0
  for (const r of SEASON_PASS_REWARDS) {
    if (r.level > passLevel.value) break
    if (r.free && !claimedFree.value.has(r.level)) n++
    if (r.paid && paidUnlocked.value && !claimedPaid.value.has(r.level)) n++
  }
  return n
})

function rewardClass(level: number, line: 'free' | 'paid'): string {
  if (level > passLevel.value) return 'opacity-40' // 未达
  const claimed = line === 'free' ? claimedFree.value.has(level) : claimedPaid.value.has(level)
  if (claimed) return 'opacity-50 grayscale'
  if (line === 'paid' && !paidUnlocked.value) return 'opacity-40'
  return ''
}

function rewardBgClass(item: PassRewardItem | null): string {
  if (!item) return 'bg-black/30'
  switch (item.kind) {
    case 'equip':
      return 'bg-gradient-to-br from-rose-700 to-fuchsia-800 border-rose-400/60'
    case 'soulStones':
      return 'bg-gradient-to-br from-violet-700 to-indigo-800 border-violet-400/60'
    case 'tickets':
      return 'bg-gradient-to-br from-sky-700 to-blue-800 border-sky-400/60'
    case 'coin':
      return 'bg-gradient-to-br from-rose-600 to-pink-700 border-rose-400/60'
    case 'gold':
    default:
      return 'bg-gradient-to-br from-amber-700 to-yellow-800 border-amber-400/60'
  }
}

async function doClaim(level: number, line: 'free' | 'paid') {
  if (!charStore.currentId) {
    emit('toast', '❌ 未选中角色')
    return
  }
  if (claiming.value) return
  claiming.value = { level, line }
  try {
    const r = await seasonStore.claimPass(charStore.currentId, level, line)
    if (!r.ok) {
      emit('toast', `❌ ${r.reason ?? '领取失败'}`)
      return
    }
    if (r.character) charStore.current = r.character
    // equip 奖励:client 把 grantedEquip push 到 huzhong inventory(server 不存完整 snapshot)
    if (r.grantedEquip && huzhongStore.equipmentInventory.length < 100) {
      huzhongStore.equipmentInventory = [...huzhongStore.equipmentInventory, r.grantedEquip]
      huzhongStore.scheduleSave()
    }
    emit('toast', `🎁 领取成功:${describePassReward(r.reward!)}`)
  } finally {
    claiming.value = null
  }
}

async function devGrantExp(amount: number) {
  if (!charStore.currentId) return
  const r = await seasonStore.grantPassExp(charStore.currentId, amount)
  if (r.ok) {
    if (r.character) charStore.current = r.character
    emit('toast', r.leveledUp ? `✨ 通行证升级!Lv.${r.passLevel}` : `+${amount} 通行证 exp`)
  }
}

onMounted(async () => {
  if (charStore.currentId && !pass.value) {
    await seasonStore.fetchPass(charStore.currentId)
  }
})
</script>

<template>
  <div
    class="relative w-[820px] max-w-[95vw] max-h-[88vh] rounded-xl overflow-hidden border-2 border-amber-700/60 shadow-2xl text-white bg-slate-900/95 flex flex-col"
  >
    <header
      class="relative flex items-center justify-center h-9 bg-gradient-to-b from-amber-900/90 to-rose-900/80 border-b border-amber-600/50 flex-shrink-0"
    >
      <h2 class="text-amber-200 text-[16px] font-bold tracking-widest drop-shadow">
        赛季通行证 (Lv.{{ passLevel }}/{{ SEASON_PASS_MAX_LEVEL }})
      </h2>
      <div class="absolute left-3 top-1/2 -translate-y-1/2 text-[11px] text-amber-200/80">
        🌀 {{ profile?.seasonId ?? '?' }} · {{ profile?.daysLeft ?? '?' }}/30 天
      </div>
      <div
        v-if="claimableCount > 0"
        class="absolute right-9 top-1/2 -translate-y-1/2 px-2 py-0.5 rounded-full bg-rose-600 text-white text-[10px] font-bold animate-pulse"
      >
        {{ claimableCount }} 待领
      </div>
      <button
        class="absolute right-2 top-1/2 -translate-y-1/2 w-6 h-6 rounded-full bg-rose-700 hover:bg-rose-600 text-white text-[14px] leading-none flex items-center justify-center"
        aria-label="关闭"
        @click="$emit('close')"
      >
        ✕
      </button>
    </header>

    <!-- 上半:状态摘要 + dev 按钮 -->
    <div
      class="px-3 py-2 border-b border-amber-700/30 text-[11px] flex items-center gap-3"
    >
      <div class="flex-1">
        <div class="text-amber-200">
          通行证经验:每 {{ passExpPerLevel }} exp 升 1 级,通关获得
        </div>
        <div class="mt-1 h-1.5 rounded bg-black/60 border border-amber-700/40 overflow-hidden">
          <div
            class="h-full bg-gradient-to-r from-amber-500 to-rose-500 transition-all duration-300"
            :style="{ width: passExpPercent + '%' }"
          />
        </div>
      </div>
      <div v-if="paidUnlocked" class="text-fuchsia-300 font-bold text-[12px]">💎 付费线已解锁</div>
      <div v-else class="text-slate-400 text-[10px]">付费线锁(需 VIP / dev)</div>
      <button
        v-if="charStore.isDev"
        class="px-2 py-1 rounded bg-fuchsia-700 hover:bg-fuchsia-600 text-[10px] font-bold"
        title="dev:加 5000 通行证 exp = 5 级"
        @click="devGrantExp(5000)"
      >
        +5 lv
      </button>
    </div>

    <!-- 表头 -->
    <div
      class="px-3 py-1.5 border-b border-amber-700/40 text-[11px] font-bold flex bg-black/40 flex-shrink-0"
    >
      <div class="w-14 text-amber-200/70">等级</div>
      <div class="flex-1 text-emerald-200">免费线</div>
      <div class="flex-1 text-fuchsia-200">付费线</div>
    </div>

    <!-- 60 行竖滚 -->
    <div class="flex-1 overflow-auto">
      <div
        v-for="r in SEASON_PASS_REWARDS"
        :key="r.level"
        class="px-3 py-1.5 border-b border-amber-700/20 flex items-center gap-2 text-[11px] transition"
        :class="r.level === passLevel ? 'bg-amber-900/40' : r.level <= passLevel ? 'bg-emerald-900/20' : ''"
      >
        <!-- Lv 标 -->
        <div
          class="w-14 flex-shrink-0 text-center font-bold tabular-nums"
          :class="
            r.level <= passLevel ? 'text-amber-200' : 'text-slate-500'
          "
        >
          Lv.{{ r.level }}
          <span v-if="r.level % 30 === 0" class="block text-[8px] text-rose-300">里程碑</span>
          <span v-else-if="r.level % 5 === 0" class="block text-[8px] text-amber-300">★</span>
        </div>
        <!-- 免费线 -->
        <div class="flex-1" :class="rewardClass(r.level, 'free')">
          <div
            v-if="r.free"
            class="flex items-center gap-1.5 px-2 py-1 rounded border"
            :class="rewardBgClass(r.free)"
          >
            <span class="flex-1 truncate">{{ describePassReward(r.free) }}</span>
            <button
              v-if="r.level <= passLevel && !claimedFree.has(r.level)"
              class="px-2 py-0.5 rounded bg-emerald-500 hover:bg-emerald-400 text-slate-900 text-[10px] font-bold transition active:scale-95 disabled:opacity-40"
              :disabled="claiming?.level === r.level && claiming?.line === 'free'"
              @click="doClaim(r.level, 'free')"
            >
              {{ claiming?.level === r.level && claiming?.line === 'free' ? '...' : '领取' }}
            </button>
            <span v-else-if="claimedFree.has(r.level)" class="text-[10px] text-emerald-300/70">
              ✓ 已领
            </span>
            <span v-else class="text-[10px] text-slate-400">未达</span>
          </div>
          <div v-else class="text-slate-500 text-[10px] italic px-2">—</div>
        </div>
        <!-- 付费线 -->
        <div class="flex-1" :class="rewardClass(r.level, 'paid')">
          <div
            v-if="r.paid"
            class="flex items-center gap-1.5 px-2 py-1 rounded border"
            :class="rewardBgClass(r.paid)"
          >
            <span class="flex-1 truncate">{{ describePassReward(r.paid) }}</span>
            <button
              v-if="paidUnlocked && r.level <= passLevel && !claimedPaid.has(r.level)"
              class="px-2 py-0.5 rounded bg-fuchsia-500 hover:bg-fuchsia-400 text-white text-[10px] font-bold transition active:scale-95 disabled:opacity-40"
              :disabled="claiming?.level === r.level && claiming?.line === 'paid'"
              @click="doClaim(r.level, 'paid')"
            >
              {{ claiming?.level === r.level && claiming?.line === 'paid' ? '...' : '领取' }}
            </button>
            <span v-else-if="claimedPaid.has(r.level)" class="text-[10px] text-fuchsia-300/70">
              ✓ 已领
            </span>
            <span v-else-if="!paidUnlocked" class="text-[10px] text-slate-400">🔒</span>
            <span v-else class="text-[10px] text-slate-400">未达</span>
          </div>
          <div v-else class="text-slate-500 text-[10px] italic px-2">—</div>
        </div>
      </div>
    </div>

    <footer
      class="px-3 py-1.5 text-[10px] text-amber-200/60 border-t border-amber-700/30 flex justify-between flex-shrink-0"
    >
      <span>通关获得 stage × 200 通行证 exp,赛季结束 passLevel 归 0(跨赛季独立)</span>
      <span>{{ claimedFree.size + claimedPaid.size }} / {{ SEASON_PASS_MAX_LEVEL * 2 }} 已领</span>
    </footer>
  </div>
</template>
