<script setup lang="ts">
/**
 * 壶中天地玩法页面(2.0)
 *
 * 体系:
 *   - 20 关递进(1~20),每战胜一关摇奖,弹窗选择 替换/丢弃
 *   - 12 槽位装备:第 1 行武器 ×3 / 第 2 行技能 ×3 / 第 3 行防具 ×3 / 第 4 行神器×2+替身
 *   - 战斗采用单回合逐步结算,飘字 + HP 动画
 *
 * 数据:
 *   - 关卡 / 装备 / 槽位: src/data/huzhongMock.ts
 *   - 战斗状态: src/stores/huzhong.ts
 *   - 奖励弹窗: src/components/feature/HuzhongRewardModal.vue
 */

import { computed, onBeforeUnmount, onMounted, ref, watch } from 'vue'
import { storeToRefs } from 'pinia'
import { useHuzhongStore } from '@/stores/huzhong'
import { useCharacterStore } from '@/stores/character'
import { useUserStore } from '@/stores/user'
import { useSeasonStore } from '@/stores/season'
import { router } from '@/router'
import { SLOT_LAYOUT, QUALITY_COLOR, huzhongAttrs } from '@/data/huzhongMock'
import { resolveEquipImage, equipTooltipText } from '@/data/huzhongExternalPool'
import HuzhongShopPanel from '@/components/feature/HuzhongShopPanel.vue'
import HuzhongBackpackPanel from '@/components/feature/HuzhongBackpackPanel.vue'
import HuzhongEnhancePanel from '@/components/feature/HuzhongEnhancePanel.vue'
import HuzhongAwakeningPanel from '@/components/feature/HuzhongAwakeningPanel.vue'
import HuzhongBuffPanel from '@/components/feature/HuzhongBuffPanel.vue'
import HuzhongSeasonPanel from '@/components/feature/HuzhongSeasonPanel.vue'
import HuzhongRuleModal from '@/components/feature/HuzhongRuleModal.vue'
import HuzhongRewardModal from '@/components/feature/HuzhongRewardModal.vue'
import HuzhongLevelsModal from '@/components/feature/HuzhongLevelsModal.vue'

// ===== Store =====
const store = useHuzhongStore()
const char = useCharacterStore()
const userStore = useUserStore()
const seasonStore = useSeasonStore()
const {
  currentStage,
  maxCleared,
  equipped,
  playerHp,
  playerHpMax,
  inBattle,
  battlePhase,
  battleResult,
  hits,
  pendingReward,
  totalPower,
} = storeToRefs(store)
const { gold, coin, tickets } = storeToRefs(char)

// ===== UI 状态 =====
type TabKey = 'equipment' | 'attrs'
type PanelKey = 'shop' | 'backpack' | 'enhance' | 'awakening' | 'buff' | 'rules' | 'titles' | 'levels' | 'season' | null

const activeTab = ref<TabKey>('equipment')
const activePanel = ref<PanelKey>(null)
const unlockDialog = ref(false)

// ===== 战斗飘字(从 store.hits 镜像,带回合压缩) =====
interface DisplayHit {
  key: number
  value: number
  side: 'p2m' | 'm2p'
  crit?: boolean
  /** V2.4 压缩字段:同一方向 + 同一时间窗内的连续 hit 会合并成一个,这里记 count */
  count?: number
}
const floatingHits = ref<DisplayHit[]>([])

/**
 * 压缩阈值:同一侧 + 时间窗 1.5s 内的连续 hit,合并成一条 "×N"
 * 5+ hit 合并用 1 条 "×5" 显示,避免后期 boss 80 回合飘字挤屏
 */
const COMPRESS_WINDOW_MS = 1500

function pushFloatingHit(h: { value: number; side: 'p2m' | 'm2p'; crit?: boolean }) {
  const now = Date.now()
  const last = floatingHits.value[floatingHits.value.length - 1]
  if (
    last &&
    last.side === h.side &&
    now - last.key < COMPRESS_WINDOW_MS &&
    (last.count ?? 1) < 99
  ) {
    last.value += h.value
    last.count = (last.count ?? 1) + 1
    if (h.crit) last.crit = true
  } else {
    floatingHits.value.push({ ...h, key: now, count: 1 })
  }
  // 保留最近 6 条
  if (floatingHits.value.length > 6) floatingHits.value.shift()
}

// ===== 屏闪(每次受到伤害时触发) =====
const flashKey = ref(0)
const flashColor = ref<'red' | 'amber'>('red')

watch(
  hits,
  (cur, prev) => {
    // 把新加入的 hit 转成飘字(带压缩)
    if (cur.length > (prev?.length ?? 0)) {
      for (let i = prev?.length ?? 0; i < cur.length; i++) {
        pushFloatingHit(cur[i]!)
      }
    }
    // 触发屏闪(只在战斗中且有新 hit 时)
    if (battlePhase.value === 'fighting' && cur.length > (prev?.length ?? 0)) {
      const lastNew = cur[cur.length - 1]
      if (lastNew) {
        flashColor.value = lastNew.side === 'p2m' ? 'red' : 'amber'
        flashKey.value++
      }
    }
  },
  { deep: true },
)

// ===== Toast =====
const toast = ref('')
let toastTimer: ReturnType<typeof setTimeout> | null = null
function showToast(msg: string) {
  toast.value = msg
  if (toastTimer) clearTimeout(toastTimer)
  toastTimer = setTimeout(() => (toast.value = ''), 2000)
}

// ===== 计算属性 =====
const playerHpPercent = computed(() => Math.max(0, (playerHp.value / playerHpMax.value) * 100))
const stageData = computed(() => store.currentStageData)
const stageProgress = computed(() => ((currentStage.value - 1) / 20) * 100)

// ===== 事件 =====
function openPanel(p: Exclude<PanelKey, null>) {
  activePanel.value = p
}
function closePanel() {
  activePanel.value = null
}

async function handleChallenge() {
  if (pendingReward.value) {
    showToast('⚠️ 请先处理上一关的奖励')
    return
  }
  if (tickets.value <= 0) {
    showToast('🎫 挑战符不足')
    return
  }
  const r = await store.challengeCurrent()
  if (!r.ok) {
    showToast(`❌ ${r.reason ?? '挑战失败'}`)
    return
  }
  if (r.win) {
    showToast(`🎉 第 ${currentStage.value} 关胜利!`)
  } else {
    showToast('💀 挑战失败,稍后再来')
  }
}

async function handleBatchChallenge(n: number) {
  if (pendingReward.value) {
    showToast('⚠️ 请先处理上一关的奖励')
    return
  }
  if (tickets.value < n) {
    showToast(`🎫 挑战符不够连续 ${n} 关`)
    return
  }
  const r = await store.challengeBatch(n)
  if (r.lost) {
    showToast(`⚔️ 连续挑战中断 · 胜 ${r.wins} 关`)
  } else {
    showToast(`✅ 连续挑战 ${r.wins} 关完成`)
  }
}

async function handleGainTimes() {
  const r = await store.gainChallengeTimes(10)
  if (r) {
    showToast('🎫 获得 10 张挑战符')
  } else {
    showToast('❌ dev grant 失败(需 dev 角色)')
  }
}

async function handleMaxClear() {
  const r = await store.maxClear(35)
  if (r) {
    showToast('⚔️ 已提升到 Lv.35(攻击 60k+)')
  } else {
    showToast('❌ 提升失败(需 dev 角色)')
  }
}

async function handleSeasonReset() {
  if (!char.currentId) {
    showToast('❌ 未选中角色')
    return
  }
  const c = await seasonStore.devReset(char.currentId)
  if (c) {
    char.current = c
    // 重置本地 huzhong state
    store.resetStages()
    showToast(`🌀 赛季重置完成(${seasonStore.profile?.seasonId ?? ''})`)
  } else {
    showToast(`❌ ${seasonStore.lastError ?? '赛季重置失败'}`)
  }
}

function closeRewardModal() {
  if (pendingReward.value) {
    showToast('⚠️ 请选择「替换」或「丢弃」')
    return
  }
}

function openEquipmentPage() {
  // 装备槽位点击走 /equipment 路由
  router.push('/equipment')
}
function openLevelsPage() {
  // 闯关入口 → 打开页内 modal(20 关水平滚动)
  activePanel.value = 'levels'
}

function openUnlockDialog() {
  unlockDialog.value = true
}

onBeforeUnmount(() => {
  if (toastTimer) clearTimeout(toastTimer)
  // 离开页面兜底 flush,避免关闭页签时漏掉最后一次 PATCH
  void store.flushSave()
})

// 进入页面:从服务端拉取(覆盖本地默认状态)
onMounted(async () => {
  // 1) 先把角色数据拉到(防 restoreSession 还没跑完的 race)
  if (char.currentId && !char.current) {
    try {
      await char.fetchCurrent()
    } catch (err) {
      console.error('[huzhong] fetchCurrent failed', err)
      // 角色不存在(服务端重启后常见)→ 清脏 currentId + 跳 /characters
      char.signOut()
      router.replace({ name: 'characters', query: { redirect: '/huzhong' } })
      return
    }
  }
  // 2) 拉壶中存档
  if (char.currentId) {
    try {
      await store.init(char.currentId)
      store.playerHp = char.hpMax
      store.playerHpMax = char.hpMax
    } catch (err) {
      console.error('[huzhong] init failed', err)
    }
  }
  // 3) 拉赛季档案(自动触发 server rollover,顺便刷 character)
  if (char.currentId) {
    const r = await seasonStore.fetch(char.currentId)
    if (r) {
      // 用 server 返回的最新 character 覆盖本地(可能刚被 rollover 重置)
      char.current = r.character
    }
  }
})

// HUD 刷新按钮:有 currentId 就再拉一次角色,没 currentId 就直接跳选角页
const reloading = ref(false)
const reloadLabel = computed(() => {
  if (reloading.value) return '加载中…'
  return char.currentId ? '🔄 重新加载角色' : '⚠️ 去选择角色'
})
async function reloadCharacter() {
  if (reloading.value) return
  if (!char.currentId) {
    router.push({ name: 'characters', query: { redirect: '/huzhong' } })
    return
  }
  reloading.value = true
  try {
    await char.fetchCurrent()
    showToast('✅ 角色已重新加载')
  } catch (err: any) {
    console.error('[huzhong] reloadCharacter failed', err)
    char.signOut()
    showToast(`❌ 角色加载失败:${err?.message ?? '未知错误'}`)
    router.push({ name: 'characters', query: { redirect: '/huzhong' } })
  } finally {
    reloading.value = false
  }
}
</script>

<template>
  <div class="fixed inset-0 overflow-hidden bg-slate-900 flex items-center justify-center">
    <div
      class="relative w-full max-w-[1280px] aspect-[16/9] mx-auto shadow-2xl ring-1 ring-amber-700/30 bg-black text-white"
    >
      <!-- ===== 背景 hztdbg.png ===== -->
      <div
        class="absolute inset-0 bg-cover bg-center"
        :style="{
          backgroundImage: 'url(/assets/bg/hztdbg.png)',
          filter: 'brightness(0.5) saturate(1.15)',
        }"
      />
      <div class="absolute inset-0 bg-gradient-to-b from-black/40 via-transparent to-black/60" />

      <!-- ===== 内容层 ===== -->
      <div class="relative h-full z-10">
        <!-- 顶 HUD -->
        <header
          class="absolute top-0 left-0 right-0 h-12 flex items-center px-3 gap-2 text-[12px] bg-gradient-to-b from-black/80 to-transparent z-20"
        >
          <div class="flex items-center gap-2">
            <div
              class="w-9 h-9 rounded-full bg-gradient-to-br from-amber-500 to-rose-700 flex items-center justify-center text-lg ring-2 ring-amber-400"
            >
              🐧
            </div>
            <span v-if="char.nickname" class="font-bold text-amber-200">{{ char.nickname }}</span>
            <button
              v-else-if="userStore.isLogin"
              class="font-bold text-rose-300 hover:text-rose-200 underline underline-offset-2 text-[11px]"
              :title="char.currentId ? '点击重新加载角色' : '点击去选择角色'"
              @click="reloadCharacter"
            >
              {{ reloadLabel }}
            </button>
            <span v-else class="font-bold text-amber-200/60">未登录</span>
          </div>
          <div class="flex items-center gap-1 ml-2">
            <button
              class="px-2 py-0.5 rounded bg-rose-700/80 hover:bg-rose-600 text-amber-100 text-[11px] border border-amber-500/40 transition active:scale-95"
              @click="openPanel('titles')"
            >
              称号
            </button>
            <button
              class="px-2 py-0.5 rounded bg-slate-700/80 hover:bg-slate-600 text-amber-100 text-[11px] border border-amber-500/40 transition active:scale-95"
              @click="openPanel('rules')"
            >
              规则
            </button>
          </div>
          <div class="flex-1" />
          <div
            v-if="seasonStore.profile"
            class="flex items-center gap-1 text-fuchsia-300 text-[12px] font-bold tabular-nums hover:text-fuchsia-200 cursor-pointer transition"
            :title="`点击打开赛季通行证 · ${seasonStore.profile.seasonId} · Lv.${seasonStore.profile.seasonLevel} · ${seasonStore.profile.seasonExp}/${seasonStore.profile.expToNext} exp`"
            @click="openPanel('season')"
          >
            <span>🌀</span>
            <span>赛季 {{ seasonStore.profile.daysLeft }}/30 天</span>
            <span class="text-amber-200/60 ml-1">Lv.{{ seasonStore.profile.seasonLevel }}</span>
          </div>
          <div class="flex items-center gap-3 font-bold tabular-nums">
            <span class="flex items-center gap-1 text-amber-300">
              <span>🪙</span>{{ gold.toLocaleString() }}
            </span>
            <span class="flex items-center gap-1 text-rose-300">
              <span>💎</span>{{ coin.toLocaleString() }}
            </span>
            <span
              class="flex items-center gap-1 text-sky-300"
              :class="{ 'text-rose-400': tickets <= 2 }"
            >
              <span>🎫</span>{{ tickets }}<span class="text-amber-200/40">/20</span>
            </span>
            <span class="flex items-center gap-1 text-cyan-300"> <span>🔮</span>0 </span>
          </div>
        </header>

        <!-- 关卡标题 + 进度 -->
        <div class="absolute top-12 left-4 z-20 flex flex-col gap-1">
          <div
            class="px-3 py-1 rounded bg-rose-700/85 border border-amber-400/60 text-amber-100 font-bold tracking-widest text-[13px] shadow"
          >
            第 {{ currentStage }} / 20 关 · {{ stageData?.name ?? '通关' }}
          </div>
          <div
            class="w-[200px] h-1.5 rounded bg-black/60 border border-amber-700/40 overflow-hidden"
          >
            <div
              class="h-full bg-gradient-to-r from-amber-500 to-rose-500 transition-all duration-500"
              :style="{ width: stageProgress + '%' }"
            />
          </div>
        </div>
        <!-- 飘字层(屏幕中央放大) -->
        <div class="absolute inset-0 pointer-events-none z-30 flex items-center justify-center">
          <div class="relative w-[800px] h-[300px]">
            <span
              v-for="(h, i) in floatingHits"
              :key="h.key"
              class="absolute left-1/2 top-1/2 text-5xl font-black drop-shadow-[0_2px_8px_rgba(0,0,0,0.8)] animate-float-up tabular-nums whitespace-nowrap"
              :class="[
                h.side === 'p2m' ? 'text-rose-300' : 'text-amber-300',
                h.crit ? 'text-6xl text-rose-100' : '',
              ]"
              :style="{
                transform: `translate(calc(-50% + ${(i % 2 === 0 ? 1 : -1) * (60 + i * 25)}px), calc(-50% - ${i * 40}px))`,
              }"
            >
              {{ h.crit ? '💥 ' : '' }}-{{ h.value.toLocaleString() }}
              <!-- V2.4 压缩徽章:同一方向 1.5s 内连续 hit 合并 -->
              <span
                v-if="(h.count ?? 1) > 1"
                class="ml-2 inline-block px-2 py-0.5 rounded-full bg-fuchsia-600/90 text-white text-[18px] font-extrabold align-middle"
                >×{{ h.count }}</span
              >
            </span>
          </div>
        </div>

        <!-- 屏闪(每次受击时全屏闪一下) -->
        <div
          v-if="flashKey > 0 && inBattle"
          :key="flashKey"
          class="absolute inset-0 pointer-events-none z-25 animate-screen-flash"
          :class="flashColor === 'red' ? 'bg-rose-500/40' : 'bg-amber-500/40'"
        />

        <!-- 大字遮罩:BATTLE / VICTORY / DEFEAT -->
        <div
          v-if="battlePhase !== 'idle'"
          class="absolute inset-0 pointer-events-none z-40 flex items-center justify-center"
        >
          <div
            :key="`${battlePhase}-${battleResult ?? ''}`"
            class="animate-battle-zoom"
            :class="[
              battlePhase === 'intro' ? 'text-rose-300' : '',
              battlePhase === 'ending' && battleResult === 'win' ? 'text-amber-300' : '',
              battlePhase === 'ending' && battleResult === 'lose' ? 'text-rose-400' : '',
            ]"
          >
            <div
              class="text-[120px] font-black tracking-widest drop-shadow-[0_0_30px_rgba(0,0,0,0.9)] animate-text-pulse"
            >
              {{
                battlePhase === 'intro'
                  ? '⚔️ BATTLE!'
                  : battlePhase === 'ending' && battleResult === 'win'
                    ? '🏆 VICTORY'
                    : battlePhase === 'ending' && battleResult === 'lose'
                      ? '💀 DEFEAT'
                      : ''
              }}
            </div>
            <div
              v-if="battlePhase === 'intro'"
              class="text-center text-amber-100 text-2xl font-bold tracking-widest mt-2 drop-shadow"
            >
              第 {{ currentStage }} 关 · {{ stageData?.name }}
            </div>
          </div>
        </div>

        <!-- 闯关入口按钮(正中央上方) -->
        <button
          type="button"
          class="absolute top-[140px] left-1/2 -translate-x-1/2 z-20 px-6 py-2.5 rounded-2xl bg-gradient-to-b from-amber-500 to-rose-700 border-2 border-amber-300 shadow-2xl shadow-rose-900/50 hover:scale-105 active:scale-95 transition-transform animate-glow flex items-center gap-2"
          aria-label="进入闯关"
          @click="openLevelsPage"
        >
          <span class="text-xl">⚔️</span>
          <span class="text-base font-extrabold text-amber-100 tracking-widest drop-shadow"
            >闯 关</span
          >
        </button>

        <!-- 左下角关卡徽章 -->
        <div
          class="absolute bottom-[170px] left-4 w-14 h-14 rounded-lg bg-gradient-to-br from-rose-600 to-rose-800 ring-2 ring-amber-300 shadow-xl flex flex-col items-center justify-center text-amber-100"
          :class="{ 'animate-pulse-ring': inBattle }"
        >
          <span class="text-[10px]">关卡</span>
          <span class="text-2xl font-extrabold leading-none tabular-nums">{{ currentStage }}</span>
        </div>
        <!-- 右侧:Tab + 12 槽位 / 属性 + 动作按钮 -->
        <aside class="absolute right-3 top-[100px] bottom-[150px] w-[280px] flex flex-col gap-2">
          <div class="flex gap-1">
            <button
              v-for="t in [
                { key: 'equipment' as TabKey, label: '装备' },
                { key: 'attrs' as TabKey, label: '属性' },
              ]"
              :key="t.key"
              class="flex-1 px-2 py-1.5 rounded-t text-[12px] font-bold border-b-2 transition active:scale-95"
              :class="
                activeTab === t.key
                  ? 'bg-amber-700/80 text-amber-100 border-amber-300'
                  : 'bg-black/60 text-amber-200/70 border-transparent hover:bg-black/80'
              "
              @click="activeTab = t.key"
            >
              {{ t.label }}
            </button>
          </div>

          <!-- 装备 Tab:4×3 槽位 -->
          <div v-if="activeTab === 'equipment'" class="flex-1 space-y-1.5 overflow-auto">
            <div v-for="(row, ri) in SLOT_LAYOUT" :key="ri" class="grid grid-cols-3 gap-1.5">
              <button
                v-for="cell in row"
                :key="cell.key"
                class="relative aspect-square rounded border bg-gradient-to-br overflow-hidden flex items-center justify-center text-2xl transition active:scale-95 hover:brightness-110"
                :class="
                  equipped[cell.key]
                    ? `${QUALITY_COLOR[equipped[cell.key]!.quality].bg} ${QUALITY_COLOR[equipped[cell.key]!.quality].border} border-2`
                    : cell.locked && !store.row4Unlocked
                      ? 'border-slate-700/40 bg-black/40 cursor-not-allowed opacity-70'
                      : 'border-amber-700/40 bg-black/40 border-dashed'
                "
                :title="
                  cell.locked && !store.row4Unlocked
                    ? '第 4 行需花费 5000 金币解锁'
                    : equipped[cell.key]
                      ? equipTooltipText(equipped[cell.key]!)
                      : cell.label
                "
                @click="
                  cell.locked && !store.row4Unlocked ? openUnlockDialog() : openEquipmentPage()
                "
              >
                <template v-if="cell.locked && !store.row4Unlocked">
                  <div class="text-2xl opacity-70">🔒</div>
                </template>
                <template v-else-if="equipped[cell.key]">
                  <img
                    v-if="resolveEquipImage(equipped[cell.key]!)"
                    :src="resolveEquipImage(equipped[cell.key]!)"
                    class="w-full h-full object-cover"
                    :alt="equipped[cell.key]!.name"
                  />
                  <span v-else class="text-2xl">{{ equipped[cell.key]!.icon }}</span>
                  <!-- 觉醒等级角标 -->
                  <span
                    v-if="(store.awakening[equipped[cell.key]!.id]?.level ?? 0) > 0"
                    class="absolute top-0 left-0 px-1 text-[8px] font-bold bg-fuchsia-700 text-white rounded-br"
                    :title="`觉醒 ${store.awakening[equipped[cell.key]!.id]!.level}/5`"
                  >
                    ⭐{{ store.awakening[equipped[cell.key]!.id]!.level }}
                  </span>
                  <!-- 强化等级角标 -->
                  <span
                    v-if="(store.enhanceLevel[cell.key] ?? 0) > 0"
                    class="absolute bottom-0 right-0 px-1 text-[8px] font-bold bg-rose-700 text-white rounded-tl"
                  >
                    +{{ store.enhanceLevel[cell.key] }}
                  </span>
                </template>
                <template v-else>
                  <span class="text-amber-200/30 text-[9px]">{{ cell.label }}</span>
                </template>
              </button>
            </div>
            <div class="text-center text-[10px] text-amber-200/50 mt-1">
              战力 {{ totalPower.toLocaleString() }}
              <span
                v-if="store.awakeningTotalPercent > 0"
                class="ml-1 text-fuchsia-300 font-bold"
                :title="`觉醒总加成:已装备 12 件的 awakening level 求和 × 30%`"
              >
                ✨ +{{ store.awakeningTotalPercent }}%
              </span>
