/**
 * 装备体系类型与常量(前后端共享)
 *
 * 原本散落在 `client/src/data/huzhongMock.ts`,后端持久化时迁到 shared
 */

/** 7 个标准化装备属性(所有武器/技能/防具/神器/替身共用) */
export const ATTR_LABELS = [
  '最终伤害加成',
  '最终伤害减免',
  '穿透',
  '力量',
  '速度',
  '敏捷',
  '抵挡',
] as const
export type AttrKey = (typeof ATTR_LABELS)[number]

/** 装备类型 */
export type EquipType = 'weapon' | 'skill' | 'hat' | 'clothes' | 'shoes' | 'artifact' | 'substitute'

/** 装备品质 */
export type EquipQuality = 'common' | 'rare' | 'epic' | 'legend' | 'mythic'

/** 12 个装备槽位 key(右侧 4×3 装备格) */
export type SlotKey =
  | 'weapon1'
  | 'weapon2'
  | 'weapon3'
  | 'skill1'
  | 'skill2'
  | 'skill3'
  | 'hat'
  | 'clothes'
  | 'shoes'
  | 'art1'
  | 'art2'
  | 'substitute'

/** 装备品中文名 */
export const QUALITY_NAME: Record<EquipQuality, string> = {
  common: '普通',
  rare: '稀有',
  epic: '史诗',
  legend: '传说',
  mythic: '神话',
}
