<script setup lang="ts">
/**
 * 觉醒面板(V3 养成线 4)
 *
 * 选中一件已装备的装备 → 用库存里的 N 件同名装备喂入 → 觉醒等级 +1
 * - 阈值递增 2/3/4/5/6(总 20 件满 5 觉)
 * - 每级 +30% 战力,5 觉 ≈3.7×(单件参考,实际公式按 awakeningSum 线性汇总)
 */
import { computed, ref } from 'vue'
import { storeToRefs } from 'pinia'
import { useHuzhongStore } from '@/stores/huzhong'
import {
  SLOT_LAYOUT,
  QUALITY_COLOR,
  QUALITY_NAME,
  type SlotKey,
  type EquipItem,
} from '@/data/huzhongMock'
import { resolveEquipImage, equipTooltipText } from '@/data/huzhongExternalPool'
import { AWAKENING_DUPLICATES_PER_LEVEL, MAX_AWAKENING } from '@ncgame/shared'

const emit = defineEmits<{
  close: []
  toast: [msg: string]
}>()

const store = useHuzhongStore()
const { equipped, awakening, equipmentInventory } = storeToRefs(store)

const selectedSlot = ref<SlotKey>('weapon1')

function getItem(slot: SlotKey): EquipItem | null {
  return equipped.value[slot]
}

/** 当前选中装备的觉醒等级 */
const currentLevel = computed<number>(() => {
  const item = getItem(selectedSlot.value)
  if (!item) return 0
  return awakening.value[item.id]?.level ?? 0
})

/** 升下一级需要多少件同名 */
const needNext = computed<number>(() => {
  const lv = currentLevel.value
  if (lv >= MAX_AWAKENING) return 0
  return AWAKENING_DUPLICATES_PER_LEVEL[lv] ?? 0
})

/** 库存里同 itemId 的件数 */
const haveNow = computed<number>(() => {
  const item = getItem(selectedSlot.value)
  if (!item) return 0
  return equipmentInventory.value.filter((i) => i.id === item.id).length
})

const canFeed = computed<boolean>(() => {
  const item = getItem(selectedSlot.value)
  if (!item) return false
  if (currentLevel.value >= MAX_AWAKENING) return false
  return haveNow.value >= needNext.value
})

const progressPercent = computed<number>(() => {
  if (needNext.value === 0) return 100
  return Math.min(100, Math.floor((haveNow.value / needNext.value) * 100))
})

async function doAwaken() {
  const r = await store.awaken(selectedSlot.value)
  if (r.ok) {
    emit('toast', `✨ 觉醒成功!⭐×${r.newLevel}(消耗 ${r.consumed} 件同名)`)
  } else {
    emit('toast', `❌ ${r.reason ?? '觉醒失败'}`)
  }
}

/** 槽位上该装备已觉醒到几级(角标显示用) */
function awakenLevelOf(slot: SlotKey): number {
  const item = getItem(slot)
  if (!item) return 0
  return awakening.value[item.id]?.level ?? 0
}

/** 当前选中装备的同名材料预览列表(库存里同 itemId 的全部),前 needNext 个标"将消耗" */
const sameNameInInventory = computed<EquipItem[]>(() => {
  const item = getItem(selectedSlot.value)
  if (!item) return []
  return equipmentInventory.value.filter((i) => i.id === item.id)
})
</script>

<template>
  <div
    class="relative w-[760px] max-w-[95vw] max-h-[88vh] rounded-xl overflow-hidden border-2 border-fuchsia-700/60 shadow-2xl text-white bg-slate-900/95"
  >
    <header
      class="relative flex items-center justify-center h-9 bg-gradient-to-b from-fuchsia-900/90 to-rose-900/80 border-b border-fuchsia-600/50"
    >
      <h2 class="text-fuchsia-200 text-[16px] font-bold tracking-widest drop-shadow">
        装备觉醒 (0~⭐×5)
      </h2>
      <div class="absolute left-3 top-1/2 -translate-y-1/2 text-[11px] text-fuchsia-200/80">
        📦 库存 {{ equipmentInventory.length }}/100
      </div>
      <button
        class="absolute right-2 top-1/2 -translate-y-1/2 w-6 h-6 rounded-full bg-rose-700 hover:bg-rose-600 text-white text-[14px] leading-none flex items-center justify-center"
        aria-label="关闭"
        @click="$emit('close')"
      >
        ✕
      </button>
    </header>

    <div class="p-3 grid grid-cols-2 gap-3" style="max-height: calc(88vh - 36px)">
      <!-- 左:12 槽位网格 -->
      <div class="space-y-2">
        <div class="text-[11px] text-fuchsia-200/70 mb-1">选择要觉醒的装备</div>
        <div v-for="(row, ri) in SLOT_LAYOUT" :key="ri" class="grid grid-cols-3 gap-1.5">
          <button
            v-for="cell in row"
            :key="cell.key"
            class="relative aspect-square rounded border-2 overflow-hidden transition active:scale-95 flex items-center justify-center text-2xl"
            :class="
              getItem(cell.key)
                ? `${QUALITY_COLOR[getItem(cell.key)!.quality].bg} ${QUALITY_COLOR[getItem(cell.key)!.quality].border}`
                : 'bg-black/40 border-amber-900/40 opacity-60'
            "
            :title="getItem(cell.key) ? equipTooltipText(getItem(cell.key)!) : cell.label"
            :disabled="!getItem(cell.key)"
            @click="selectedSlot = cell.key"
          >
            <template v-if="getItem(cell.key)">
              <img
                v-if="resolveEquipImage(getItem(cell.key)!)"
                :src="resolveEquipImage(getItem(cell.key)!)"
                class="w-full h-full object-cover"
                :alt="getItem(cell.key)!.name"
              />
              <span v-else class="text-3xl">{{ getItem(cell.key)!.icon }}</span>
            </template>
            <template v-else>
              <span class="text-amber-200/30 text-[10px]">{{ cell.label }}</span>
            </template>
            <!-- 当前觉醒等级角标 -->
            <span
              v-if="awakenLevelOf(cell.key) > 0"
              class="absolute top-0 left-0 px-1 text-[9px] font-bold bg-fuchsia-700 text-white rounded-br"
              :title="`觉醒 ${awakenLevelOf(cell.key)}/5`"
            >
              ⭐{{ awakenLevelOf(cell.key) }}
            </span>
            <div
              v-if="selectedSlot === cell.key"
              class="absolute inset-0 ring-2 ring-fuchsia-300 rounded"
            />
          </button>
        </div>
      </div>

      <!-- 右:详情 + 喂入 -->
      <div class="space-y-2">
        <!-- 选中装备详情 -->
        <div
          v-if="getItem(selectedSlot)"
          class="p-3 rounded-lg bg-black/40 border border-fuchsia-700/40"
        >
          <div class="flex items-center gap-2 mb-2">
            <img
              v-if="resolveEquipImage(getItem(selectedSlot)!)"
              :src="resolveEquipImage(getItem(selectedSlot)!)"
              class="w-10 h-10 object-cover flex-shrink-0"
              :alt="getItem(selectedSlot)!.name"
            />
            <div v-else class="text-3xl">{{ getItem(selectedSlot)!.icon }}</div>
            <div class="flex-1">
              <div
                class="font-bold text-[14px]"
                :class="QUALITY_COLOR[getItem(selectedSlot)!.quality].text"
              >
                {{ getItem(selectedSlot)!.name }}
                <span class="text-fuchsia-300 text-[12px] ml-1">
                  ⭐{{ currentLevel }}/{{ MAX_AWAKENING }}
                </span>
              </div>
              <div class="text-fuchsia-200/60 text-[11px]">
                {{ QUALITY_NAME[getItem(selectedSlot)!.quality] }} · id
                {{ getItem(selectedSlot)!.id }}
              </div>
            </div>
          </div>
          <!-- 当前觉醒收益 -->
          <div
            class="text-[11px] px-2 py-1 rounded bg-fuchsia-900/30 border border-fuchsia-700/40 text-fuchsia-200"
          >
            当前觉醒收益(单件):+{{ currentLevel * 30 }}% 攻击
            <span v-if="currentLevel < MAX_AWAKENING" class="text-fuchsia-300">
              → 下一级:+{{ (currentLevel + 1) * 30 }}%
            </span>
          </div>
        </div>
        <div
          v-else
          class="p-3 rounded-lg bg-black/40 border border-fuchsia-700/40 text-center text-fuchsia-200/50 text-[12px]"
        >
          槽位「{{ selectedSlot }}」暂无装备<br />请先装备一件后再觉醒
        </div>

        <!-- 进度 + 喂入 -->
        <div class="p-3 rounded-lg bg-fuchsia-900/20 border border-fuchsia-700/40 space-y-2">
          <div v-if="currentLevel >= MAX_AWAKENING" class="text-center text-fuchsia-300 font-bold">
            🏆 已满 5 觉,无法继续
          </div>
          <template v-else-if="getItem(selectedSlot)">
            <div class="flex justify-between text-[12px] text-fuchsia-200">
              <span>同名材料:</span>
              <span class="tabular-nums font-bold">
                <span :class="canFeed ? 'text-emerald-300' : 'text-rose-300'">
                  {{ haveNow }}
                </span>
                / {{ needNext }}
              </span>
            </div>
            <div class="h-2 rounded bg-black/60 border border-fuchsia-700/40 overflow-hidden">
              <div
                class="h-full bg-gradient-to-r from-fuchsia-500 to-rose-500 transition-all duration-300"
                :style="{ width: progressPercent + '%' }"
              />
            </div>
            <div class="text-[10px] text-fuchsia-200/60">
              觉醒下一级阈值:{{ needNext }} 件同名「{{ getItem(selectedSlot)!.name }}」(从库存消耗)
            </div>
            <button
              class="w-full py-1.5 rounded bg-gradient-to-r from-fuchsia-600 to-rose-600 text-white font-bold text-[13px] hover:brightness-110 active:scale-95 disabled:opacity-40 disabled:cursor-not-allowed transition"
              :disabled="!canFeed"
              @click="doAwaken"
            >
              <template v-if="canFeed">✨ 觉醒 → ⭐{{ currentLevel + 1 }}</template>
              <template v-else>需要 {{ needNext - haveNow }} 件同名材料</template>
            </button>
          </template>
        </div>

        <!-- 提示 -->
        <div class="px-2 text-[10px] text-fuchsia-200/50 leading-relaxed">
          觉醒后该装备永久 +30% 攻击/级。觉醒材料来源:被换下的旧装备 + 战斗后选「加入背包」的奖励。
        </div>

        <!-- 同名材料预览 -->
        <div
          v-if="getItem(selectedSlot) && sameNameInInventory.length > 0"
          class="p-2 rounded-lg bg-black/40 border border-fuchsia-700/40"
        >
          <div class="text-[11px] text-fuchsia-200 mb-1 flex items-center justify-between">
            <span>库存同名「{{ getItem(selectedSlot)!.name }}」:{{ sameNameInInventory.length }} 件</span>
            <span class="text-fuchsia-300/60 text-[10px]"
              >前 {{ Math.min(needNext, sameNameInInventory.length) }} 件将被消耗</span
            >
          </div>
          <div class="grid grid-cols-10 gap-1">
            <div
              v-for="(it, idx) in sameNameInInventory.slice(0, 20)"
              :key="`prev-${idx}`"
              class="relative aspect-square rounded border overflow-hidden"
              :class="
                idx < needNext
                  ? `${QUALITY_COLOR[it.quality].bg} ${QUALITY_COLOR[it.quality].border} ring-1 ring-rose-400`
                  : `${QUALITY_COLOR[it.quality].bg} ${QUALITY_COLOR[it.quality].border} opacity-50`
              "
              :title="
                idx < needNext
                  ? `将被消耗 (${idx + 1}/${needNext})`
                  : '暂留库存'
              "
            >
              <img
                v-if="resolveEquipImage(it)"
                :src="resolveEquipImage(it)"
                class="w-full h-full object-cover"
                :alt="it.name"
              />
              <div v-else class="w-full h-full flex items-center justify-center text-base">
                {{ it.icon }}
              </div>
              <span
                v-if="(it.star ?? 0) > 0"
                class="absolute top-0 left-0 text-[7px] px-0.5 bg-rose-700/90 text-white"
                >★{{ it.star }}</span
              >
            </div>
            <div
              v-if="sameNameInInventory.length > 20"
              class="aspect-square rounded border border-fuchsia-700/40 bg-black/40 flex items-center justify-center text-[10px] text-fuchsia-200/60"
            >
              +{{ sameNameInInventory.length - 20 }}
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>
